INSERT INTO `controllTxtItems`
VALUES ('controll','emails','comeback','html','Controll-Default: This is controll-emails-comeback-html<br/>Custom HTML that can replaced with a custom value in the ConTroll Admin App under RegAdmin/Edit Custom Text.<br/>Default text display can be suppressed in the configuration file.'),
('controll','emails','comeback','text','Controll-Default: This is controll-emails-comeback-text\nCustom HTML that can replaced with a custom value in the Controll Admin App under Edit Custom Text.\n Default text can be suppressed in the configuration file.'),
('controll','emails','expire','html','<p><strong>Hello!</strong></p>\n<p>Dear [[FirstName]],</p>\n<p>You are receiving this email because you created a [[label]] membership for #conname# at a discounted rate on [[createdate]], but never paid for it.\nThat discounted rate will expire on [[enddate]].  If the membership is not paid before that date, we will cancel that unpaid membership\nand you will need to purchase one at the then current rate to attend.</p>\n<p>Please sign in to our registration portal at <a href=\"#server#\">#server#</a> and click on the \"Pay Total Amount Due\" button to pay for your membership.</p>\n<p>If you no longer desire this membership, either sign on  and use the \"Add To/Edit Cart\" button to remove the membership from your\naccount or just let it expire and it will be removed automatically.</p>\n<p>We look forward to seeing you at #conname#.</p>\n<p>If you have any issues in paying for your membership or removing it from your account, please reach out to us at\n<a href=\"mailto:#regadminemail#\">#regadminemail#</a>.\n<p>Thank you,<br/>\n#conname# Registration\n</p>'),
('controll','emails','expire','text','Dear [[FirstName]],\n\nYou are receiving this email because you created a [[label]] membership for #conname# at a discounted rate on [[createdate]], but never paid for it.\nThat discounted rate will expire on [[enddate]].  If the membership is not paid before that date, we will cancel that unpaid membership\nand you will need to purchase one at the then current rate to attend.\n\nPlease sign in to our registration portal at #server# and click on the \"Pay Total Amount Due\" button to pay for your membership.\n\nIf you no longer desire this membership, either sign on  and use the \"Add To/Edit Cart\" button to remove the membership from your account or just let it\nexpire and it will be removed automatically.\n\nWe look forward to seeing you at #conname#.\n\nIf you have any issues in paying for your membership or removing it from your account, please reach out to us at #regadminemail#.\n\nThank you,\n#conname# Registration\n'),
('controll','emails','marketing','html','<p><strong>Hello!</strong></p>\n<p>#label# is almost upon us!</p>\n<p>You are receiving this email because your email address is associated with a valid registration to attend last year&rsquo;s convention, but we don&rsquo;t have you registered for this year&rsquo;s convention. You can always register on-site, but you can save money by purchasing your membership in advance at #server#. The registration site will allow you to see the status of your current memberships and has the ability to group your family together by letting you \"manage\" their accounts.</p>\n<p>Note: having an account on our system does not indicate you have a membership.&nbsp; You must add a membership to your cart using the \"Add To/Edit Cart\" button on the line with your name, verify your details, policies, and interests, and then add&nbsp; membership(s) to your cart.&nbsp; You then can save the cart and return to pay for your memberships.&nbsp; There is currently a discounted rate that expires 11/10, if the membership is not paid for by that date, it will be cancelled and you will need to buy one at the door at the \"door rates.\"</p>\n<p>This year, we are at the same hotel, #hotelname#, at #hoteladdr#. Please register for rooms as soon as possible as the block will be closing soon. You can find a link to the hotel registration site on our website at <a title=\"Hotel Information Web Page\" href=\"#hotelwebsite#\">#hotelwebsite#</a>.</p>\n<p>Our programming team is putting together a great schedule for us this year, and you can take a look at it at&nbsp;<a title=\"ComCl&aacute;r Schedule Page\" href=\"#schedulepage#\">#schedulepage#</a>.</p>\n<p>Information about other activities, as well as our Guests of Honor, can be found on our website at <a title=\"#label# Web Site\" href=\"#website#\">#website#</a>.</p>\n<p>The #org# (#orgabv#) is dedicated to providing a comfortable and harassment-free environment for everyone at #conname# and other #orgabv#-sponsored events. For specific information, including our full Anti-Harassment Policy, see <a title=\"#label# Policy\" href=\"#policy#\">#policy#</a>.</p>\n<p>If you have any further questions, please feel free to contact us at <a href=\"mailto:#feedbackemail#\">#feedbackemail#</a>, or visit our website for information on how to contact individual departments.</p>\n<p>We hope to see you at the convention!</p>\n<p>#conname# Registration Team</p>\n<p>If you wish to opt out of this marketing email going forward, please email us at <a href=\"mailto:#regadminemail#\">#regadminemail#</a> or send us postal mail at:</p>\n<p>#label#<br>PO BOX 8303<br>Philadelphia, PA 19101-8303</p>'),
('controll','emails','marketing','text','Hello! \n\n#label# is almost upon us! \n\nYou are receiving this email because your email address is associated with a valid registration to attend last year\'s convention, but we don\'t have you registered for this year\'s convention. You can always register on-site, but you can save money by purchasing your membership in advance at #server#. The registration site will allow you to see the status of your current memberships and has the ability to group your family together by letting you \"manage\" their accounts.\n\nNote: having an account on our system does not indicate you have a membership.  You must add a membership to your cart using the \"Add To/Edit Cart\" button on the line with your name, verify your details, policies, and interests, and then add  membership(s) to your cart.  You then can save the cart and return to pay for your memberships.  There is currently a discounted rate that expires 11/10, if the membership is not paid for by that date, it will be cancelled and you will need to buy one at the door at the \"door rates.\" \n\nThis year, we are at the same hotel, #hotelname#, at #hoteladdr#. Please register for rooms as soon as possible as the block will be closing soon. You can find a link to the hotel registration site on our website at #hotelwebsite#. \n\nOur programming team is putting together a great schedule for us this year, and you will be able to soon take a look at it at #schedulepage#. \n\nInformation about other activities, as well as our Guests of Honor, can be found on our website at #website#. \n\nThe #org# (#orgabv#) is dedicated to providing a comfortable and harassment-free environment for everyone at #conname# and other #orgabv#-sponsored events. For specific information, including our full Anti-Harassment Policy, see #policy#. \n\nIf you have any further questions, please feel free to contact us at #feedbackemail#, or visit our website for information on how to contact individual departments. \n\nWe hope to see you at the convention! \n\n#conname Registration Team \n\nIf you wish to opt out of this marketing email going forward, please email us at #regadminemail# or send us postal mail at:\n\n#label#\nPO BOX 8303\nPhiladelphia, PA 19101-8303\n'),
('controll','emails','noMembership','html','<p><strong>Hello!</strong></p>\n<p>Dear [[FirstName]],</p>\n<p>You are receiving this email because you created an account in our registration system, but you never adding a membership to your account.&nbsp; Just telling the system your age does not register you for the convention.&nbsp; You need to add a membership to your cart and then save the cart to return to the main screen to pay for your membership.<br><br>Attending #conname# requires a paid membership and since our rates go up shortly, we though we would remind you of this and give you a chance to save a few dollars by registering now.</p>\n<p>Please sign in to our registration portal at <a href=\"#server#\">#server#</a> and click on the \"Add To/Edit Cart\" button on the line with your name and ID number. This will take you to a page to start the process. Since our memberships are age based you will need to verify your age as of the start of #conname#. Once you\'ve done that and verified your information, if you have not already verified it, you will be taken to the cart page to add items to your cart.&nbsp; Click on the blue buttons to chose which memberships to add to your cart.</p>\n<p>Once you have your membership in the cart, please click the \"Save, Add Another Membership or Pay for Cart\" button to return to the main screen to pay for your registration.<br><br>Use the Pay Total Amount due portion to pay for your membership. We securely accept credit cards using Square. #conname# never sees your credit card number, instead that is entered directly into Square for us to process the purchase.<br><br>We look forward to seeing you at #conname#.</p>\n<p>If you have any issues please reach out to us at <a href=\"mailto:#regadminemail#\">#regadminemail#</a>.</p>\n<p>Thank you,<br>#conname# Registration</p>'),
('controll','emails','noMembership','text','Dear [[FirstName]],\n\nYou are receiving this email because you created an account in our registration system, but you never adding a membership to your account. Just telling the system your age does not register you for the convention. You need to add a membership to your cart and then save the cart to return to the main screen to pay for your membership.\n\nAttending #conname# requires a paid membership and since our rates go up shortly, we though we would remind you of this and give you a chance to save a few dollars by registering now.\n\nPlease sign in to our registration portal at #server# and click on the \"Add To/Edit Cart\" button on the line with your name and ID number. This will take you to a page to start the process. Since our memberships are age based you will need to verify your age as of the start of #conname#. Once you\'ve done that and verified your information, if you have not already verified it, you will be taken to the cart page to add items to your cart. Click on the blue buttons to chose which memberships to add to your cart.\n\nOnce you have your membership in the cart, please click the \"Save, Add Another Membership or Pay for Cart\" button to return to the main screen to pay for your registration.\n\nUse the Pay Total Amount due portion to pay for your membership. We securely accept credit cards using Square. #conname# never sees your credit card number, instead that is entered directly into Square for us to process the purchase.\n\nWe look forward to seeing you at #conname#.\n'),
('controll','emails','reminder','html','<p>You are receiving this email because your email address is associated with a valid registration to attend this year&rsquo;s convention. To check the status of your, or the rest of your family&rsquo;s, registration you can always visit the registration portal at #server#.</p>\n<p>This year we are at the same hotel, which is now the #hotelname#, at #hoteladdr#. Badges can be picked up or purchased at #conname# Registration, which is #pickupareatext#. #addlpickuptext#</p>\n<p>Our programming team has put together a great schedule for us this year, and you can take a look at it at #schedulepage# on your computer or portable device. Information about other activities, as well as our Guests of Honor, can be found on our website at #website#.</p>\n<p>The #org# (#orgabv#) is dedicated to providing a comfortable and harassment-free environment for everyone at #conname# and other #orgabv#-sponsored events. For specific information, including our full Anti-Harassment Policy, see #policy#.</p>\n<p>If you have any further questions, please feel free to contact us at #feedbackemail#, or visit our website for information on how to contact individual departments.</p>\n<p><strong>See you at the convention!</strong></p>\n<p><strong>Additional Information:</strong></p>\n<ul>\n<li><strong><span class=\"s1\">Where do I get my badge?</span></strong>\n<ul>\n<li><span class=\"s1\">If you come in the front door of the hotel, continue past the hotel registration desk to the pre-function space.<span class=\"Apple-converted-space\">&nbsp; </span>Registration is just through the entrance to the pre-function space on the right.</span></li>\n<li><span class=\"s1\">If you come in the side door from the parking lot, registration is rightget in front of you in the pre-function space.</span></li>\n</ul>\n</li>\n</ul>\n<p style=\"padding-left: 40px;\"><span class=\"s1\">Get in line for Check-In, and have your ID ready.</span></p>\n<ul>\n<li><strong><span class=\"s1\">Registration hours are</span></strong></li>\n<li style=\"list-style-type: none;\">\n<ul>\n<li class=\"p1\"><span class=\"s1\">Friday: </span><span class=\"s1\">3pm &ndash; 8pm</span></li>\n<li class=\"p1\"><span class=\"s1\">Saturday: </span><span class=\"s1\">9am &ndash; 7pm</span></li>\n<li class=\"p1\"><span class=\"s1\">Sunday: 9</span><span class=\"s1\">am &ndash; 1pm</span></li>\n</ul>\n</li>\n</ul>\n<ul>\n<li class=\"p1\"><strong><span class=\"s1\">Do I have to show ID?</span></strong>\n<ul>\n<li class=\"p1\"><span class=\"s1\">Yes. If you pre-purchased a badge, we would like to make sure tat no one else picks up your badge. We are very reasonable about what we consider valid ID; we just need to know the badge is going to the right person.</span></li>\n</ul>\n</li>\n<li class=\"p1\"><span class=\"s1\"><strong>Remember a mask strongly recommended at #conname.<br><br></strong></span></li>\n<li class=\"p1\"><strong><span class=\"s1\">Can I pick up my spouse/girlfriend/child&rsquo;s membership as well as my own?</span></strong>\n<ul>\n<li class=\"p1\"><span class=\"s1\">Maybe! You can pick up someone else&rsquo;s membership&nbsp;<strong>IF</strong> one of the following is true:</span>\n<ul>\n<li class=\"p1\"><span class=\"s1\">The two memberships share a last name.</span></li>\n<li class=\"p1\"><span class=\"s1\">The two memberships share an address.</span></li>\n<li class=\"p1\"><span class=\"s1\">The two memberships were purchased on the same transaction.</span></li>\n</ul>\n</li>\n<li class=\"p1\"><span class=\"s1\">You must have ID for both memberships.</span></li>\n<li class=\"p1\"><span class=\"s1\">If you are picking up a membership for someone else, we will also request that you leave us with a cell phone number where we can reach you at con, in case they come looking for their badge at Registration before they find you.</span></li>\n</ul>\n</li>\n</ul>\n<ul>\n<li class=\"p1\"><strong><span class=\"s1\">I changed my mind about my badge name! I just came up with the coolest thing, but I put something on my form that I hate now!</span></strong>\n<ul>\n<li class=\"p1\"><span class=\"s1\">That&rsquo;s okay! When you come to pick up your badge, just let us know you&rsquo;d like to change your badge name before we print it out, and we can make the change at the door.</span></li>\n</ul>\n</li>\n</ul>\n<ul>\n<li class=\"p1\"><strong><span class=\"s1\">We don&rsquo;t need no stinkin&rsquo; badges!</span></strong>\n<ul>\n<li class=\"p1\"><span class=\"s1\">Our badges don&rsquo;t stink, and yes, you do need one.&nbsp;</span></li>\n<li class=\"p1\"><span class=\"s1\">All #conname# members are required to be have a badge at all times in #conname# spaces. </span></li>\n<li class=\"p1\"><span class=\"s1\">The badge should be worn so as to be clearly visible and must be presented to any #conname# volunteer checking badges on behalf of the convention.</span></li>\n<li class=\"p1\"><span class=\"s1\">We encourage members to wear their badges above the waist because a higher number of badges are lost when worn at hip level.</span></li>\n<li class=\"p1\"><span class=\"s1\">If you do lose your badge, you can check at Registration or the Lost and Found at Ops to see if it has been turned in</span></li>\n<li class=\"p1\"><span class=\"s1\">Most conventions require you to purchase a new membership if your original badge is lost and has not been found, and that is an option. Such purchases are not refundable if the badge is later located.</span></li>\n<li class=\"p1\"><span class=\"s1\">Alternatively, if the registration lead can confirm that someone has purchased or otherwise been granted a currently valid membership to #conname, they may, at their discretion, issue a replacement badge.<span class=\"Apple-converted-space\">&nbsp; </span>A donation of at least $20 to #org# is requested for that service.</span></li>\n</ul>\n</li>\n</ul>\n<ul>\n<li class=\"p1\"><strong><span class=\"s1\">What about Participants, Dealers, and Artists?</span></strong>\n<ul>\n<li class=\"p1\"><span class=\"s1\"\">You should be receiving soon or have already received a separate email from your respective departments with further information.</span></li>\n<li class=\"p1\"><span class=\"s1\">All badges, independent of your role at #conname#, are picked up at Registration!</span></li>\n</ul>\n</li>\n</ul>\n<p class=\"p1\"><span class=\"s1\">You are receiving this email because your email address is associated with a valid membership for #label#. You will receive a post-con survey, and then no further emails from us, unless we need to contact you individually. If you wish to opt out of the survey email, please email us at <a href=\"mailto:#regadminemail#\">#</a></span><a href=\"mailto:#regadminemail#\"><span class=\"s1\">regadminemail#.</span></a></p>\n<p class=\"p1\">#label#<br><span class=\"s1\">PO BOX 8303<br></span><span class=\"s1\">Philadelphia, PA 19101-8303</span></p>'),
('controll','emails','reminder','text','#label# is almost upon us!\n\nYou are receiving this email because your email address is associated with a valid registration to attend this year\'s convention. To check the status of your, or the rest of your family\'s, registration you can always visit the registration portal at #server#.\n\nThis year we are at the same hotel, which is now the #hotelname#, at #hoteladdr#. Badges can be picked up or purchased at #conname# Registration, which is #pickupareatext#. #addlpickuptext#\n\nOur programming team has put together a great schedule for us this year, and you can take a look at it at #schedulepage# on your computer or portable device. Information about other activities, as well as our Guests of Honor, can be found on our website at #website#.\n\nThe #org# (#orgabv#) is dedicated to providing a comfortable and harassment-free environment for everyone at #conname# and other #orgabv#-sponsored events. For specific information, including our full Anti-Harassment Policy, see #policy#.\n\nIf you have any further questions, please feel free to contact us at #feedbackemail#, or visit our website for information on how to contact individual departments.\n\n\nSee you at the convention!\n\nAdditional Information:\n\nWhere do I get my badge?\n  * If you come in the front door of the hotel, continue past the hotel registration desk to the pre-function space.  Registration is just through the entrance to the pre-function space on the right.\n  * If you come in the side door from the parking lot, registration is right in front of you in the pre-function space.\n\nGet in line for Check-In, and have your ID ready.\n\nRegistration hours are\n  * Friday: 3pm - 8pm\n  * Saturday: 9am - 7pm\n  * Sunday: 9am - 1pm\n  \nDo I have to show ID?\n  * Yes. If you pre-purchased a badge, we would like to make sure tat no one else picks up your badge. We are very reasonable about what we consider valid ID; we just need to know the badge is going to the right person.\n\nRemember a mask strongly recommended at #conname.\n\nCan I pick up my spouse/girlfriend/child’s membership as well as my own?\n  * Maybe! You can pick up someone else’s membership IF one of the following is true:\n  * The two memberships share a last name.\n  * The two memberships share an address.\n  * The two memberships were purchased on the same transaction.\n  * You must have ID for both memberships.\n  * If you are picking up a membership for someone else, we will also request that you leave us with a cell phone number where we can reach you at con, in case they come looking for their badge at Registration before they find you.\n\nI changed my mind about my badge name! I just came up with the coolest thing, but I put something on my form that I hate now!\n  * That’s okay! When you come to pick up your badge, just let us know you’d like to change your badge name before we print it out, and we can make the change at the door.\n\nWe don’t need no stinkin’ badges!\n  * Our badges don’t stink, and yes, you do need one. \n  * All #conname# members are required to be have a badge at all times in #conname# spaces.\n  * The badge should be worn so as to be clearly visible and must be presented to any #conname# volunteer checking badges on behalf of the convention.\n  * We encourage members to wear their badges above the waist because a higher number of badges are lost when worn at hip level.\n  * If you do lose your badge, you can check at Registration or the Lost and Found at Ops to see if it has been turned in\n  * Most conventions require you to purchase a new membership if your original badge is lost and has not been found, and that is an option. Such purchases are not refundable if the badge is later located.\n  * Alternatively, if the registration lead can confirm that someone has purchased or otherwise been granted a currently valid membership to #conname, they may, at their discretion, issue a replacement badge.  A donation of at least $20 to #org# is requested for that service.\n\nWhat about Participants, Dealers, and Artists?\n  * You should be receiving soon or have already received a separate email from your respective departments with further information.\n  * All badges, independent of your role at #conname#, are picked up at Registration!\n\nYou are receiving this email because your email address is associated with a valid membership for #label#. You will receive a post-con survey, and then no further emails from us, unless we need to contact you individually. If you wish to opt out of the survey email, please email us at #regadminemail#.\n\n#label#\nPO BOX 8303\nPhiladelphia, PA 19101-8303\n\n'),
('controll','emails','survey','html','Dear [[FirstName]],\n<p>Thank you for attending #label#. You are receiving this email because your email address is associated with a registration that attended this year. We have a short survey we would like you to complete that will help is improve #conname#.</p>\n<p><a href=\"#survey_url#\">Take the #label# Post Convention Feedback Survey</a></p>\n<p>We look forward to reviewing your comments to help us improve #conname#.</p>\n<br>\n<p>If you have any issues please reach out to us at <a href=\"mailto:#regadminemail#\">#regadminemail#</a>.</p>\n<p>Thank you,<br>#conname# Registration</p>'),
('controll','emails','survey','text','Dear [[FirstName]],\n\nThank you for attending #label#. You are receiving this email because your email address is associated with a registration that attended this year. We have a short survey we would like you to complete that will help is improve #conname#.\n\nTake the #label# Post Convention Feedback Survey: #survey_url#\n\nWe look forward to reviewing your comments to help us improve #conname#.\n\nIf you have any issues please reach out to us at #regadminemail#.\n\nThank you,\n#conname# Registration\n'),
('exhibitor','emails','invReminder','html','<p>Dear [[FirstName]],</p>\n<p>This is a reminder that have not yet registered the items you are bringing to #label#.</p>\n<p>Please sign into the portal at #vendor.artistsite# and click the \"Open Item Registration\" button.</p>\n<p>Thank you,<br/>#vendor.artist#</p>'),
('exhibitor','emails','invReminder','text','Dear [[FirstName]],\n\nThis is a reminder that have not yet registered the items you are bringing to #label#.\n\nPlease sign into the portal at #vendor.artistsite# and click the \"Open Item Registration\" button.\n\nThank you,\n#vendor.artist#\n'),
('exhibitor','index','email','mailinInvHTML','<p class=\"p2\"><span class=\"s1\">Dear [[EXHIBITOR_NAME]]</span><span class=\"s1\">,</span></p>\n<p class=\"p2\"><span class=\"s1\">Welcome to the&nbsp;</span>[[CON_NAME]] [[REGION_NAME]]<span class=\"s1\">.</span></p>\n<p class=\"p2\"><span class=\"s1\">Your Artist Number is </span>[[ARTIST_NUMBER]]<span class=\"s1\">.</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * FILLING OUT THE ONLINE ITEM REGISTRATION * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">By using the Online Iitem Registration, you will be able to enter your art directly into the Art Show database.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You can edit your entries and remove them if needed, then print out your bid sheets, sales tags and controll sheets.</span></p>\n<p class=\"p2\"><span class=\"s1\">Sign in to the Artist Portal at&nbsp;<a href=\"[[ARTIST_PORTAL]]\">[[ARTIST_PORTAL]]</a>.&nbsp;<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You will see your personal and Art Show information.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>Select the \"Open Item Registration\" to enter your art into the inventory.</span></p>\n<p class=\"p2\"><span class=\"s1\">Please email&nbsp;</span>[[OWNER_NAME]]&nbsp;<span class=\"s1\">at&nbsp;<a href=\"mailto:[[OWNER_EMAIL]]\">[[OWNER_EMAIL]]</a><span class=\"Apple-converted-space\">&nbsp;</span>if you have any questions about the forms</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * * MAIL-IN DEADLINE * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">Please have your art received no later than Tuesday, November 18th, please account for postal delays. Please ship to:</span></p>\n<p style=\"margin-right: .3in; mso-pagination: lines-together; page-break-after: avoid; mso-list: l0 level1 lfo1;\"><span style=\"font-size: 12.0pt;\">Philcon Art Show c/o<br>Joni Brill Dashoff<br><span style=\"mso-spacerun: yes;\">&nbsp;</span>830 Barlow St.<br><span style=\"mso-spacerun: yes;\">&nbsp;</span>Philadelphia, PA 19116</span></p>\n<p style=\"margin-right: .3in; mso-pagination: lines-together; page-break-after: avoid; mso-list: l0 level1 lfo1;\"><span style=\"font-size: 12.0pt;\">Once your art is turned over to the carrier, please send tracking information to: <a href=\"mailto:[[OWNER_EMAIL]]\">[[OWNER_EMAIL]]</a>.</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * * RETURN SHIPPING * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">Please include with your art, either a pre-paid shipping label, or enclose a check to cover estimated shipping costs.<span class=\"Apple-converted-space\"> If you have a preferred carrier, please let us know. </span>Unsold art will be shipped out within five days of the end of the convention.</span></p>\n<p class=\"p2\"><span class=\"s1\">Thank you,</span></p>\n<p class=\"p2\"><span class=\"s1\">- Joni Brill Dashoff &amp; Saul Jaffe, Philcon Art Show Directors</span></p>'),
('exhibitor','index','email','mailinInvText','<p class=\"p2\"><span class=\"s1\">Dear [[EXHIBITOR_NAME]]</span><span class=\"s1\">,</span></p>\n<p class=\"p2\"><span class=\"s1\">Welcome to the&nbsp;</span>[[CON_NAME]] [[REGION_NAME]]<span class=\"s1\">.</span></p>\n<p class=\"p2\"><span class=\"s1\">Your Artist Number is </span>[[ARTIST_NUMBER]]<span class=\"s1\">.</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * FILLING OUT THE ONLINE ITEM REGISTRATION * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">By using the Online Iitem Registration, you will be able to enter your art directly into the Art Show database.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You can edit your entries and remove them if needed, then print out your bid sheets, sales tags and controll sheets.</span></p>\n<p class=\"p2\"><span class=\"s1\">Sign in to the Artist Portal at [[ARTIST_PORTAL]]. <span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You will see your personal and Art Show information.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>Select the \"Open Item Registration\" to enter your art into the inventory.</span></p>\n<p class=\"p2\"><span class=\"s1\">Please email&nbsp;</span>[[OWNER_NAME]]&nbsp;<span class=\"s1\">at [[OWNER_EMAIL]]<span class=\"Apple-converted-space\">&nbsp;</span>if you have any questions about the forms.</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * * MAIL-IN DEADLINE * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">Please have your art received no later than Tuesday, November 18th, please account for postal delays. Please ship to:</span></p>\n<p style=\"margin-right: .3in; mso-pagination: lines-together; page-break-after: avoid; mso-list: l0 level1 lfo1;\"><span style=\"font-size: 12.0pt;\">Philcon Art Show c/o<br>Joni Brill Dashoff<br><span style=\"mso-spacerun: yes;\">&nbsp;</span>830 Barlow St.<br><span style=\"mso-spacerun: yes;\">&nbsp;</span>Philadelphia, PA 19116</span></p>\n<p style=\"margin-right: .3in; mso-pagination: lines-together; page-break-after: avoid; mso-list: l0 level1 lfo1;\"><span style=\"font-size: 12.0pt;\">Once your art is turned over to the carrier, please send tracking information to: [[OWNER_EMAIL]].</span></p>\n<h2 class=\"p2\"><span class=\"s1\">* * * * * * * * RETURN SHIPPING * * * * * * * *</span></h2>\n<p class=\"p2\"><span class=\"s1\">Please include with your art, either a pre-paid shipping label, or enclose a check to cover estimated shipping costs.<span class=\"Apple-converted-space\"> If you have a preferred carrier, please let us know. </span>Unsold art will be shipped out within five days of the end of the convention.</span></p>\n<p class=\"p2\"><span class=\"s1\">Thank you,</span></p>\n<p class=\"p2\"><span class=\"s1\">- Joni Brill Dashoff &amp; Saul Jaffe, Philcon Art Show Directors</span></p>'),
('exhibitor','index','email','onsiteInvHTML','<p class=\"p1\"><span class=\"s1\">Dear [[EXHIBITOR_NAME]]</span><span class=\"s1\">,</span></p>\n<p class=\"p1\"><span class=\"s1\">Welcome to the&nbsp;</span><span class=\"s1\">[[CON_NAME]] [[REGION_NAME]].</span></p>\n<p class=\"p1\"><span class=\"s1\">Your Artist Number is&nbsp;</span>[[ARTIST_NUMBER]]<span class=\"s1\">.</span></p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * FILLING OUT THE ONLINE ITEM REGISTRATION * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">By using the Online Iitem Registration, you will be able to enter your art directly into the Art Show database.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You can edit your entries and remove them if needed, then print out your bid sheets, sales tags and controll sheets.</span></p>\n<p class=\"p1\"><span class=\"s1\">Sign in to the Artist Portal at&nbsp;<a href=\"[[ARTIST_PORTAL]]\">[[ARTIST_PORTAL]]</a>.&nbsp;<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You will see your personal and Art Show information.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>Select the \"Open Item Registration\" enter your art.</span></p>\n<p class=\"p1\"><span class=\"s1\">Please email&nbsp;</span><span class=\"s1\">[[OWNER_NAME]]</span><span class=\"s1\">&nbsp;at&nbsp;<a href=\"mailto:[[OWNER_EMAIL]]\">[[OWNER_EMAIL]]</a><span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>if you have any questions about the forms.</span></p>\n<p>&nbsp;</p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * * FRIDAY ARTIST CHECK-IN * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">Artist Check-in starts at 3PM on Friday.<span class=\"Apple-converted-space\"> &nbsp;</span></span><!-- [if !supportLists]--><span style=\"font-size: 14px;\">Bring your Control Sheets, Bid Sheets, and Print Sales Tags, and your art to the Art Show. See a staff member at the Control Desk to begin the check-in process. </span></p>\n<p class=\"p1\"><span class=\"s1\">We will give you your space/location, and you can hang or set up your art.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>We provide hanging hardware, including the extra-long hooks for the Print Shop.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>When your art has been set up, come back to the Control Desk to have one of our staff finish the check-in process.</span></p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * * ARTIST CHECK-OUT * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">The Art Auction starts at 1:00PM on Sunday, general sales begin at 1:30PM. Artist Check-out runs from 1:30-3PM. Pack up your art, then bring all bid sheets to the desk to be checked out.<span class=\"Apple-converted-space\">&nbsp;</span></span><span style=\"font-size: 14px;\">Checks for art sold at the show will be mailed approximately one month after the convention. Checks will be made payable to the artist unless otherwise requested by the artist.</span></p>\n<p class=\"p1\"><span class=\"s1\">Thank you,</span></p>\n<p class=\"p1\"><span class=\"s1\">- Joni Brill Dashoff &amp; Saul Jaffe, Philcon Art Show Directors</span></p>'),
('exhibitor','index','email','onsiteInvText','<p class=\"p1\"><span class=\"s1\">Dear [[EXHIBITOR_NAME]]</span><span class=\"s1\">,</span></p>\n<p class=\"p1\"><span class=\"s1\">Welcome to the&nbsp;</span><span class=\"s1\">[[CON_NAME]] [[REGION_NAME]].</span></p>\n<p class=\"p1\"><span class=\"s1\">Your Artist Number is&nbsp;</span>[[ARTIST_NUMBER]]<span class=\"s1\">.</span></p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * FILLING OUT THE ONLINE ITEM REGISTRATION * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">By using the Online Iitem Registration, you will be able to enter your art directly into the Art Show database.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You can edit your entries and remove them if needed, then print out your bid sheets, sales tags and controll sheets.</span></p>\n<p class=\"p1\"><span class=\"s1\">Sign in to the Artist Portal at [[ARTIST_PORTAL]]. <span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>You will see your personal and Art Show information.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>Select the \"Open Item Registration\" enter your art.</span></p>\n<p class=\"p1\"><span class=\"s1\">Please email&nbsp;</span><span class=\"s1\">[[OWNER_NAME]]</span><span class=\"s1\"> at [[OWNER_EMAIL]] if you have any questions about the forms.</span></p>\n<p>&nbsp;</p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * * FRIDAY ARTIST CHECK-IN * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">Artist Check-in starts at 3PM on Friday.<span class=\"Apple-converted-space\"> &nbsp;</span></span><!-- [if !supportLists]--><span style=\"font-size: 14px;\">Bring your Control Sheets, Bid Sheets, and Print Sales Tags, and your art to the Art Show. See a staff member at the Control Desk to begin the check-in process. </span></p>\n<p class=\"p1\"><span class=\"s1\">We will give you your space/location, and you can hang or set up your art.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>We provide hanging hardware, including the extra-long hooks for the Print Shop.<span class=\"Apple-converted-space\">&nbsp;&nbsp;</span>When your art has been set up, come back to the Control Desk to have one of our staff finish the check-in process.</span></p>\n<h2 class=\"p1\"><span class=\"s1\">* * * * * * * * ARTIST CHECK-OUT * * * * * * * *</span></h2>\n<p class=\"p1\"><span class=\"s1\">The Art Auction starts at 1:00PM on Sunday, general sales begin at 1:30PM. Artist Check-out runs from 1:30-3PM. Pack up your art, then bring all bid sheets to the desk to be checked out.<span class=\"Apple-converted-space\">&nbsp;</span></span><span style=\"font-size: 14px;\">Checks for art sold at the show will be mailed approximately one month after the convention. Checks will be made payable to the artist unless otherwise requested by the artist.</span></p>\n<p class=\"p1\"><span class=\"s1\">Thank you,</span></p>\n<p class=\"p1\"><span class=\"s1\">- Joni Brill Dashoff &amp; Saul Jaffe, Philcon Art Show Directors</span></p>'),
